var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤? 아샤! 어디있나! 아샤!","JPN":"アーシャ？　アーシャ！　どこにいる！　アーシャ！","ENG":"Asha? Asha! Where are you?! ASHA!","TWN":"阿莎？阿莎！你在哪！阿莎！"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님? 왜 그러세요?","JPN":"アーディティヤ様？　どうされました？","ENG":"Miss Aditya? What’s wrong?","TWN":"阿迪亞？你幹嘛？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"꿈이었나.","JPN":"夢……だったか。","ENG":"Was I dreaming?","TWN":"剛剛是做夢嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"지독한 악몽을 꾼 것 같군.","JPN":"……はあ。悪夢にもほどがある。","ENG":"I must've had a terrible nightmare.","TWN":"我好像做了個很可怕的夢。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"악몽이요?","JPN":"悪夢ですか？","ENG":"A nightmare?","TWN":"惡夢嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그래. 내가 능력을 제어하지 못해서 네가 다치는 꿈이었다.","JPN":"ああ、私が自分の能力を制御しきれず、君を傷つけてしまう夢だ。","ENG":"Yes. I dreamt that you got hurt because I couldn't control my powers.","TWN":"嗯，我夢見自己無法控制能力，害你受傷。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 몸에서 빛이 사방으로 퍼져나가더니…….","JPN":"私の身体から全方向に光が放たれ……","ENG":"I had light emitting all over my body and...","TWN":"光從我的身體四散開來……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"괜찮아요. 아디트야 님. 지독한 꿈을 꾸셨네요.","JPN":"大丈夫ですよ、アーディティヤ様。酷い夢を見たんですね。","ENG":"It's all right, Miss Aditya. It was only a bad dream.","TWN":"沒事的，阿迪亞，你只是做惡夢而已。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이젠 괜찮다. 네가 나 때문에 그런 일을 당하지 않았으면 됐어.","JPN":"もう大丈夫だ。君さえ無事ならそれでいい。","ENG":"I'm fine now. I just hope that nothing like that will happen to you because of me.","TWN":"現在沒事了，只要不會連累你就好。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그럼 이제 출발할 시간이군.","JPN":"それでは、そろそろ出発しよう。","ENG":"It's time to go.","TWN":"差不多該出發了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"준비해라, 아샤.","JPN":"準備しろ、アーシャ。","ENG":"Get ready, Asha.","TWN":"準備好，阿莎。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤?","JPN":"アーシャ？","ENG":"Asha?","TWN":"阿莎？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"윽…… 아디트야…… 님? 어째서……?","JPN":"くっ……アーディティヤ様……？　どうして……？","ENG":"Ngh... Miss... Aditya? Why...?","TWN":"唔……阿迪亞……？為什麼……？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L34_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"갑자기…… 아디트야 님의 몸에서 빛이 터져 나와서……. ","JPN":"突然……アーディティヤ様の身体が光り出して…… ","ENG":"A sudden light... burst out from your body, and...","TWN":"突然……從你身上發出光……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"사방이…… 너무 뜨거워요…….","JPN":"周囲が……すごく熱くなって……","ENG":"it's burning... everywhere...","TWN":"周圍……好燙……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤!!!","JPN":"アーシャ！！！","ENG":"ASHA!!!","TWN":"阿莎！！！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아니야…… 아니야…… 이건……!","JPN":"違う……違う……これは……！","ENG":"No... No... This isn't...!","TWN":"不是的……不……這……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망…… 치세요. 아디트야 님…….","JPN":"逃げて……ください。アーディティヤ様……","ENG":"R... un, Miss Aditya...","TWN":"快……逃。阿迪亞……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"<color=#ff3636>결국 이번에도 혼자 남게 되겠네요.</color>","JPN":"<color=#ff3636>結局、今回もまた一人になりますね。</color>","ENG":"<color=#ff3636>Seems that you're all alone again.</color>","TWN":"<color=#ff3636>看來這次也會是獨自一人吧。</color>"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"어두워","JPN":"暗い。","ENG":"It's dark...","TWN":"好黑。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"우리는 언제까지 기다려야 하지?","JPN":"いつまで待っていたらいいの？","ENG":"How much longer do we have to wait?","TWN":"我們到底要等到什麼時候？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"이대로 우릴 내버려 둘 셈이야?","JPN":"このまま見捨てるつもりか？","ENG":"Are you going to just leave us here?","TWN":"是打算就這樣把我們丟在這裡嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"우리를 구해줘. 아디트야.","JPN":"助けてくれ、アーディティヤ。","ENG":"Save us, Aditya.","TWN":"救救我們，阿迪亞。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"너무 뜨겁고…… 답답해…….","JPN":"熱くて……すごく苦しい……","ENG":"It's so hot in here... I can't breathe...","TWN":"好燙……好悶……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"당신만…… 당신만 아니었다면…….","JPN":"あなたの……あなたのせいで……","ENG":"If... If it weren't for you...","TWN":"要不是你……要不是你……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너희도…… 나 때문에 이렇게 된 건가?","JPN":"君たちも……そうなのか？","ENG":"Did I... do this to you?","TWN":"你們……也是被我害的嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나를 믿고 따르다가…… 제어되지 않는 내 힘에 휘말려서…….","JPN":"私を信じていたのに……私の力の犠牲になったのか？","ENG":"You trusted me, and... because I couldn't control my powers...","TWN":"信任我而追隨我……結果卻因為我無法控制力量而……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"결국 모두가 당신 곁을 떠나게 만들겠지.","JPN":"結局、あなたのそばには誰も残らない。","ENG":"In the end, everyone will leave your side.","TWN":"最後，所有人都會離開你。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_GIRL_SHADOW","text":{"KOREA":"태양이 가까울수록 주변은 불타버리기 마련이니까.","JPN":"太陽に近づくと、すべては燃え尽きてしまう。","ENG":"Because everything too close to the sun will eventually be in flames.","TWN":"越是靠近太陽，身體就越容易灼傷。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_GIRL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"이봐요. 정신이 드십니까? 이봐요!","JPN":"しっかりしてください！　聞こえますか！","ENG":"Hey, are you all right? Hello?!","TWN":"小姐、小姐，你醒了嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……꿈이었군.","JPN":"……夢だったか。","ENG":"...It was a dream.","TWN":"……原來是做夢。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"사막 한복판에 쓰러져 계시면 위험합니다.","JPN":"危険ですよ、砂漠のど真ん中で倒れていたら。","ENG":"It's dangerous to be lying down in the middle of the desert.","TWN":"倒在沙漠中是很危險的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"제가 지나가는 길에 발견해서 망정이지, 큰일 날 뻔했어요.","JPN":"私が見つけたからよかったものの、危ないところでした。","ENG":"Thank goodness I found you. You could've been in grave danger.","TWN":"你差點就出事了，幸好我路過發現你。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"온몸이 상처투성이던데 무슨 일이 있었던 겁니까?","JPN":"身体中傷だらけですが、いったい何があったんですか？","ENG":"You're covered in scars. What happened to you?","TWN":"你渾身都是傷，是發生什麼事嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……침식체에게 습격을 받았다.","JPN":"……侵食体に襲われた。","ENG":"...I was attacked by a C.O.","TWN":"……我遭到侵蝕體的攻擊。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"맞아…… 아샤는…… 그 침식체한테 삼켜졌지.","JPN":"そうだ……アーシャは……あの侵食体に飲み込まれてしまった。","ENG":"Right... The C.O... swallowed Asha.","TWN":"沒錯……阿莎她……被侵蝕體給吞吃了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"제어하지 못하는 힘은 아무런 쓸모도 없는 법인데.","JPN":"制御できない力なんか、なんの役にも立たない。","ENG":"Uncontrollable power is worthless.","TWN":"無法控制的力量毫無用處。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"어째서 그런 중요한 사실을 이제야 기억해 낸거지?","JPN":"どうしてそんな重要なことを、もっと早くに思い出せなかったんだろう。","ENG":"So, why did I forget this important thing?","TWN":"為什麼我現在才想起這麼重要的事？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"한심하군.","JPN":"情けない。","ENG":"I'm pathetic.","TWN":"真是可悲。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"결국 또 나 혼자 살아남았다는 건가.","JPN":"結局、また一人で生き延びてしまった。","ENG":"Am I the only one left again?","TWN":"結果又只剩我一個人活下來嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"너무 무서웠어요. 여기서 침식체한테 죽을지도 모른다는 생각이 들어서…….","JPN":"すごく怖かったです。このまま侵食体に殺されてしまうのかと思ったら……","ENG":"I was scared for my life. Thinking that a C.O. would kill me on the spot...","TWN":"好可怕，我會在這裡被侵蝕體殺死嗎……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WIND_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그래서…… 살고 싶어서…….","JPN":"でも……なんとか生きたいと思って……","ENG":"And... because I wanted to live...","TWN":"但是……我想活下去……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"침식체한테 습격을……?","JPN":"侵食体に襲われた……？","ENG":"Attacked by a C.O...?","TWN":"被侵蝕體攻擊……？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_QM","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_QM","text":{"KOREA":"그렇다면 혹시…… 천년의 도시, 에리두를 삼킨 그 전설 속 침식체를 조우하셨습니까?","JPN":"あなた、もしかして……千年の都市、エリドゥを飲み込んだ伝説の侵食体に遭遇したんですか？","ENG":"Then... you encountered the legendary C.O. that is said to have swallowed Eridu, the millennial city?","TWN":"難道……你遇到那個傳說中吞噬掉千年之城埃里都的侵蝕體嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};